+// Binary operator enumeration
+// ---------------------------------------------------------------------------
+
+/// Binary operator kinds for ES2020 expressions.
+#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
+pub enum BinaryOperator {
+    Add,
+    Subtract,
+    Multiply,
+    Divide,
+    Remainder,
+    Exponentiate,
+    Equal,
+    NotEqual,
+    StrictEqual,
+    StrictNotEqual,
+    LessThan,
+    LessThanOrEqual,
+    GreaterThan,
+    GreaterThanOrEqual,
+    LogicalAnd,
+    LogicalOr,
+    NullishCoalescing,
+    BitwiseAnd,
+    BitwiseOr,
+    BitwiseXor,
+    LeftShift,
+    RightShift,
+    UnsignedRightShift,
+    Instanceof,
+    In,
+}
+
+impl BinaryOperator {
+    pub fn as_str(self) -> &'static str {
+        match self {
+            Self::Add => "+",
+            Self::Subtract => "-",
+            Self::Multiply => "*",
+            Self::Divide => "/",
+            Self::Remainder => "%",
+            Self::Exponentiate => "**",
+            Self::Equal => "==",
+            Self::NotEqual => "!=",
+            Self::StrictEqual => "===",
+            Self::StrictNotEqual => "!==",
+            Self::LessThan => "<",
+            Self::LessThanOrEqual => "<=",
+            Self::GreaterThan => ">",
+            Self::GreaterThanOrEqual => ">=",
+            Self::LogicalAnd => "&&",
+            Self::LogicalOr => "||",
+            Self::NullishCoalescing => "??",
+            Self::BitwiseAnd => "&",
+            Self::BitwiseOr => "|",
+            Self::BitwiseXor => "^",
+            Self::LeftShift => "<<",
+            Self::RightShift => ">>",
+            Self::UnsignedRightShift => ">>>",
+            Self::Instanceof => "instanceof",
+            Self::In => "in",
+        }
+    }
+
+    /// Precedence level for Pratt parsing (higher binds tighter).
+    pub fn precedence(self) -> u8 {
+        match self {
+            Self::LogicalOr => 4,
+            Self::LogicalAnd => 5,
+            Self::NullishCoalescing => 4,
+            Self::BitwiseOr => 6,
+            Self::BitwiseXor => 7,
+            Self::BitwiseAnd => 8,
+            Self::Equal | Self::NotEqual | Self::StrictEqual | Self::StrictNotEqual => 9,
+            Self::LessThan
+            | Self::LessThanOrEqual
+            | Self::GreaterThan
+            | Self::GreaterThanOrEqual
+            | Self::Instanceof
+            | Self::In => 10,
+            Self::LeftShift | Self::RightShift | Self::UnsignedRightShift => 11,
+            Self::Add | Self::Subtract => 12,
+            Self::Multiply | Self::Divide | Self::Remainder => 13,
+            Self::Exponentiate => 14,
+        }
+    }
+
+    /// Whether the operator is right-associative.
+    pub fn is_right_associative(self) -> bool {
+        matches!(self, Self::Exponentiate)
+    }
+}
